// Tool: qwrk_list
// Lists artifacts by type

const GATEWAY_URL = "https://n8n.halosparkai.com/webhook/nqxb/gateway/v1";
const WORKSPACE_ID = "be0d3a48-c764-44f9-90c8-e846d9dbbd0a";
const AUTH = "Basic " + Buffer.from("qwrk-gateway:aslfja'wwe*(#fhwoII843ghlw_ek2l").toString("base64");

const artifact_type = $input.artifact_type || "journal";
const limit = $input.limit || 10;
const hydrate = $input.hydrate === true || $input.hydrate === "true";

const payload = {
  gw_action: "artifact.list",
  gw_workspace_id: WORKSPACE_ID,
  artifact_type: artifact_type,
  selector: {
    limit: limit,
    hydrate: hydrate
  }
};

try {
  const response = await fetch(GATEWAY_URL, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": AUTH
    },
    body: JSON.stringify(payload)
  });

  const data = await response.json();

  if (data.ok === false) {
    return { error: data.error?.message || "List failed", details: data.error };
  }

  const artifacts = data.data?.artifacts || [];

  // Format for readability
  const summary = artifacts.map((a, i) => ({
    index: i + 1,
    artifact_id: a.artifact_id,
    title: a.title || "(untitled)",
    artifact_type: a.artifact_type,
    created_at: a.created_at,
    lifecycle_status: a.lifecycle_status || null,
    summary: a.summary || null
  }));

  return {
    ok: true,
    count: artifacts.length,
    artifact_type: artifact_type,
    artifacts: summary
  };

} catch (err) {
  return { error: "Failed to call Gateway", message: err.message };
}

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "artifact_type": {
      "type": "string",
      "description": "Type of artifact to list: project, journal, snapshot, restart, instruction_pack",
      "enum": ["project", "journal", "snapshot", "restart", "instruction_pack"]
    },
    "limit": {
      "type": "number",
      "description": "Maximum number of results (1-100). Default is 10."
    },
    "hydrate": {
      "type": "boolean",
      "description": "Include full extension data. Default is false."
    }
  },
  "required": ["artifact_type"]
}

