// Tool: qwrk_save_project
// Create a new project

const GATEWAY_URL = "https://n8n.halosparkai.com/webhook/nqxb/gateway/v1";
const WORKSPACE_ID = "be0d3a48-c764-44f9-90c8-e846d9dbbd0a";
const OWNER_USER_ID = "7097c16c-ed88-4e49-983f-1de80e5cfcea";
const AUTH = "Basic " + Buffer.from("qwrk-gateway:aslfja'wwe*(#fhwoII843ghlw_ek2l").toString("base64");

const title = $input.title;
const summary = $input.summary || null;
const lifecycle_stage = $input.lifecycle_stage || "seed";

if (!title) {
  return { error: "Title is required for projects" };
}

// Validate lifecycle_stage
const validStages = ["seed", "sapling", "tree"];
if (!validStages.includes(lifecycle_stage)) {
  return { error: `Invalid lifecycle_stage. Must be one of: ${validStages.join(", ")}` };
}

const payload = {
  gw_action: "artifact.save",
  gw_workspace_id: WORKSPACE_ID,
  owner_user_id: OWNER_USER_ID,
  artifact_type: "project",
  title: title,
  summary: summary,
  content: {},
  extension: {
    lifecycle_stage: lifecycle_stage
  }
};

try {
  const response = await fetch(GATEWAY_URL, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": AUTH
    },
    body: JSON.stringify(payload)
  });

  const data = await response.json();

  if (data.ok === false) {
    return { error: data.error?.message || "Save failed", details: data.error };
  }

  return {
    ok: true,
    message: "Project saved successfully",
    artifact_id: data.artifact_id,
    title: title,
    lifecycle_stage: lifecycle_stage
  };

} catch (err) {
  return { error: "Failed to call Gateway", message: err.message };
}

